const SECTIONS = ['mods', 'maps', 'skins', 'textures', 'shaders', 'seeds'];
const CATEGORIES = {
  mods: ['Оружие', 'Мебель', 'Транспорт', 'Мобы', 'Броня'],
  maps: ['Приключения', 'Выживание', 'Паркур', 'Хоррор', 'Город'],
  skins: ['Аниме', 'Супергерои', 'Фильмы', 'Игры', 'Животные'],
  textures: ['Реалистичные', 'Мультяшные', 'Средневековье', 'Современные', 'Faithful'],
  shaders: ['Реалистичные', 'Мультяшные', 'Яркие', 'Тёмные', 'Мягкие'],
  seeds: ['Деревни', 'Храмы', 'Спавн', 'Биомы', 'Пещеры']
};

const pages = [];
for (const section of SECTIONS) {
  for (let p = 1; p <= 5; p++) {
    pages.push({
      _section: section,
      _page: p,
      _categories: CATEGORIES[section],
      url: p === 1 ? `https://mcpehub.org/${section}/` : `https://mcpehub.org/${section}/page/${p}/`
    });
  }
}

return pages.map(p => ({ json: p }));

const genItems = $('Generate URLs1').all();
const idx = $itemIndex;
const meta = genItems[idx]?.json || {};

const section = meta._section || 'unknown';
const page = meta._page || 0;
const categories = meta._categories || ['General'];

const input = $input.item.json;
let html = '';
if (typeof input === 'string') html = input;
else if (input && typeof input.data === 'string') html = input.data;
else if (input && typeof input.body === 'string') html = input.body;

if (!html || html.length < 500) {
  return { json: { _empty: true, section: section, page: page, items: [], count: 0 } };
}

const results = [];
const articles = html.match(/<article[^>]*>[\s\S]*?<\/article>/gi) || [];

for (const article of articles) {
  const urlMatch = article.match(/<a[^>]*href="([^"]+\.html)"/);
  if (!urlMatch) continue;

  let pageUrl = urlMatch[1];
  if (pageUrl.startsWith('/')) pageUrl = 'https://mcpehub.org' + pageUrl;

  const titleMatch = article.match(/<h2[^>]*>([^<]+)<\/h2>/);
  const title = titleMatch ? titleMatch[1].trim() : '';

  const imgMatch = article.match(/<img[^>]*src="([^"]+)"/);
  let imageUrl = imgMatch ? imgMatch[1] : '';
  if (imageUrl.startsWith('/')) imageUrl = 'https://mcpehub.org' + imageUrl;

  const descMatch = article.match(/<p[^>]*class="[^"]*black[^"]*regular[^"]*"[^>]*>([^<]+)<\/p>/);
  const desc = descMatch ? descMatch[1].trim() : '';

  if (title && pageUrl && imageUrl) {
    results.push({
      section: section,
      category: categories[results.length % categories.length],
      title: title,
      page_url: pageUrl,
      image_url: imageUrl,
      description: desc
    });
  }
}

return { json: { section: section, page: page, items: results, count: results.length } };

const data = $json;
const pages = data.all_pages || [];

let allItems = [];
for (const page of pages) {
  if (page.items && Array.isArray(page.items)) {
    allItems = allItems.concat(page.items);
  }
}

// Дедупликация
const unique = [];
const seen = new Set();
for (const item of allItems) {
  if (item.page_url && !seen.has(item.page_url)) {
    seen.add(item.page_url);
    unique.push(item);
  }
}

// Группировка с лимитом 50 на секцию
const bySection = {};
for (const item of unique) {
  if (!bySection[item.section]) bySection[item.section] = [];
  if (bySection[item.section].length < 50) {
    bySection[item.section].push(item);
  }
}

// Формируем items для скачивания картинок
const items = [];
let idx = 0;
for (const section of Object.keys(bySection)) {
