// Переименовываем binary файл
const newBinary = {};
if (binary) {
  const key = Object.keys(binary)[0];
  if (key && binary[key]) {
    newBinary[item.image_filename] = {
      ...binary[key],
      fileName: item.image_filename
    };
  }
}

return {
  json: {
    id: item.id,
    section: item.section,
    category: item.category,
    image: item.image_filename,
    file: '',
    title: item.title.substring(0, 50),
    description: item.description.substring(0, 500),
    qa_score: item.qa_score
  },
  binary: newBinary
};

const data = $json;
const items = data.final_items || [];

console.log(`Final approved items: ${items.length}`);

// Подсчёт по секциям
const stats = {};
for (const item of items) {
  stats[item.section] = (stats[item.section] || 0) + 1;
}
console.log('Stats:', stats);

// Формируем CSV
const headers = ['id', 'section', 'category', 'image', 'file', 'title', 'description'];
let csv = headers.join(',') + '\n';

items.forEach(item => {
  const title = (item.title || '').replace(/"/g, '').replace(/\n/g, ' ');
  const desc = (item.description || '').replace(/"/g, '').replace(/\n/g, ' ');
  const row = [item.id, item.section, item.category, item.image, item.file || '', `"${title}"`, `"${desc}"`];
  csv += row.join(',') + '\n';
});

const b64 = Buffer.from(csv, 'utf-8').toString('base64');
const filename = `minecraft_content_${Date.now()}`;

// Собираем все binary из Finalize Items
const allBinaries = $('Finalize Items1').all();
const binaryData = { 'content.csv': { data: b64, mimeType: 'text/csv', fileName: 'content.csv' } };

for (const item of allBinaries) {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      binaryData[key] = item.binary[key];
    }
  }
}

return {
  json: { total_items: items.length, filename: filename, stats: stats },
  binary: binaryData
};

